UPDATE PI_ER2_CONNECT_HIST SET
	RSP_DTM = DATE_FORMAT(NOW(), '%Y%m%d%H%i%s'),
	RSP_CD = #{rsp_cd},
	RSP_MSG = #{rsp_msg}
WHERE 1=1
	AND ID = #{id}
	AND RECON_ID = #{recon_id}
	AND URL = #{url}
	AND METHOD = #{method}

